  private void processZip64ExtendedInformation(final DataInput in) throws IOException {
    final long sizeOfCD = in.readLong();
    final long startingDiskNumber = in.readLong();
    final long numberOfDisks = in.readLong();
    final long directoryStartIndex = in.readLong();
    final long numberOfEntriesInFirstDisk = in.readLong();
    archive.discard((int) (sizeOfCD - OFFSET_SIZEOFCD));
    if (startingDiskNumber > nextDiskNumber || startingDiskNumber < 0L) {
        throw new ZipEncodingException("Illegal starting disk number");
    }
    nextDiskNumber = startingDiskNumber;
    if (numberOfDisks < nextDiskNumber || numberOfDisks > 0x7fffffffL) {
       throw new ZipEncodingException("Invalid value for number of disks.");
    }
    final DiskBuilder diskBldr = new DiskBuilder((int) numberOfDisks,
        (int) numberOfEntriesInFirstDisk, (int) startingDiskNumber);
    for (;;) {
      final int idx = diskBldr.incrementIndexes();
      if (idx >= OFFSET_CENTRALDIRECTORY) {
          break;
      }
      discardIfOutside(archive.skipBytes(OFFSET_DISKNUMBER), true);
      discardIfOutside(archive.skipBytes(OFFSET_DISKSTART), true);
      discardIfOutside(archive.skipBytes(OFFSET_DISKENTRYCOUNT), true);
      discardIfOutside(archive.skipBytes(OFFSET_TOTALENTRYCOUNT), true);
      discardIfOutside(archive.skipBytes(OFFSET_COMMENTLEN), true);
      discardIfOutside(archive.skipBytes(OFFSET_COMMENT), true);
    }
    final long commentLength = archive.readUnsignedInt();
    if (commentLength > Integer.MAX_VALUE) {
        throw new IllegalArgumentException("Comment length too big");
    }
    discardIfOutside(archive.skipBytes((int) commentLength), true);
}

